/**
 * A SemVer range expression: a union (OR) of {@link ComparatorSet}s. Supports node-semver syntax — hyphen ranges (`1.0.0 - 2.0.0`), X-ranges (`1.x`, `*`), tilde (`~1.2.3`), caret (`^1.2.3`) and `||` unions — which parsing desugars into primitive comparators and normalizes.
 *
 * @example
 * ```ts
 * import { Range, SemVer } from "@effected/semver";
 * import { Effect } from "effect";
 *
 * const program = Effect.gen(function* () {
 *   const range = yield* Range.parse("^1.0.0");
 *   const version = yield* SemVer.parse("1.5.0");
 *   console.log(range.test(version)); // true
 * });
 * ```
 *
 * @public
 */

