/**
 * The difference between two {@link SemVer} versions: the classification of the change plus signed numeric deltas. A `Schema.TaggedClass` — the one concept in this package where serialized tag discrimination earns its keep.
 *
 * The `type` field is the highest-precedence field that differs: `"major"`, `"minor"`, `"patch"`, `"prerelease"` (only prerelease identifiers differ), `"build"` (only build metadata differs) or `"none"`.
 *
 * @example
 * ```ts
 * import { SemVer, VersionDiff } from "@effected/semver";
 * import { Effect } from "effect";
 *
 * const program = Effect.gen(function* () {
 *   const a = yield* SemVer.parse("1.2.3");
 *   const b = yield* SemVer.parse("2.0.0");
 *   const diff = VersionDiff.between(a, b);
 *   console.log(diff.type);  // "major"
 *   console.log(diff.major); // 1
 * });
